329			break;
330	
331		case S_IFREG:
332			/*
333			 * We do not send the blob in case of a retry, so do not
334			 * bother reading it at all.
335			 */
336			if (dco && dco->state == CE_RETRY) {
337				new_blob = NULL;
338				size = 0;
339			} else {
340				new_blob = read_blob_entry(ce, &size);
341				if (!new_blob)
